#include <stdio.h>
#include <stdlib.h>
#include <string.h>

void generateParenthesis(int n, char** results, int* count) {
    char* str = (char*)malloc((2 * n + 1) * sizeof(char));
    int index = 0;

    void _generateParenthesis(int pos, int open, int close) {
        if (close == n) {
            str[pos] = '\0';
            results[*count] = strdup(str);
            (*count)++;
            return;
        } else {
            if (open > close) {
                str[pos] = ')';
                _generateParenthesis(pos + 1, open, close + 1);
            }
            if (open < n) {
                str[pos] = '(';
                _generateParenthesis(pos + 1, open + 1, close);
            }
        }
    }

    _generateParenthesis(0, 0, 0);
    free(str);
}

int compare(const void* a, const void* b) {
    return strcmp(*(const char**)a, *(const char**)b);
}

int main() {
    int T;
    scanf("%d", &T);

    while (T--) {
        int N;
        scanf("%d", &N);

        int max_results = 1 << (2 * N);  // Upper bound on number of results
        char** results = (char**)malloc(max_results * sizeof(char*));
        int count = 0;

        generateParenthesis(N, results, &count);
        qsort(results, count, sizeof(char*), compare);

        printf("%d\n", count);
        for (int i = 0; i < count; i++) {
            printf("%s\n", results[i]);
            free(results[i]);
        }
        free(results);
    }

    return 0;
}

