import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.io.PrintWriter;
import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.StringTokenizer;

public class Main {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        PrintWriter pw = new PrintWriter(System.out);
        int T = Integer.parseInt(br.readLine());
        for (int t = 0; t < T; t++) {
            int N = Integer.parseInt(br.readLine());

            List<String> result = new ArrayList<>();
            generateParenthesis(N, result);
            Collections.sort(result);
            pw.println(result.size());
            for (String s : result) {
                pw.println(s);
            }
        }
        pw.close();
    }

    public static void generateParenthesis(int n, List<String> result) {
        generateParenthesisHelper(n, 0, 0, new StringBuilder(), result);
    }

    public static void generateParenthesisHelper(int n, int open, int close, StringBuilder sb, List<String> result) {
        if (close == n) {
            result.add(sb.toString());
            return;
        }
        if (open < n) {
            sb.append('(');
            generateParenthesisHelper(n, open + 1, close, sb, result);
            sb.deleteCharAt(sb.length() - 1);
        }
        if (close < open) {
            sb.append(')');
            generateParenthesisHelper(n, open, close + 1, sb, result);
            sb.deleteCharAt(sb.length() - 1);
        }
    }
}

