function generateParenthesis(n, result) {
    function generateParenthesisHelper(n, open, close, sb, result) {
        if (close === n) {
            result.push(sb.join(''));
            return;
        }
        if (open < n) {
            sb.push('(');
            generateParenthesisHelper(n, open + 1, close, sb, result);
            sb.pop();
        }
        if (close < open) {
            sb.push(')');
            generateParenthesisHelper(n, open, close + 1, sb, result);
            sb.pop();
        }
    }
    generateParenthesisHelper(n, 0, 0, [], result);
}

